```php
function findMaxMin($array) {
    $n = count($array);

    // Initialize variables
    $max = $array[0];
    $min = $array[0];
    $maxIndices = [];
    $minIndices = [];

    // Iterate through the array
    for ($i = 0; $i < $n; $i++) {
        // Update max value and indices if necessary
        if ($array[$i] > $max) {
            $max = $array[$i];
            $maxIndices = [$i];
        } elseif ($array[$i] == $max) {
            $maxIndices[] = $i;
        }

        // Update min value and indices if necessary
        if ($array[$i] < $min) {
            $min = $array[$i];
            $minIndices = [$i];
        } elseif ($array[$i] == $min) {
            $minIndices[] = $i;
        }
    }

    // Return the max and min values along with their indices
    return [
        'max' => $max,
        'maxIndices' => $maxIndices,
        'min' => $min,
        'minIndices' => $minIndices
    ];
}

// Example usage
$array = [1, 5, 2, 7, 2, 9, 7, 5];
$result = findMaxMin($array);

echo "Max value: " . $result['max'] . "<br>";
echo "Max indices: " . implode(', ', $result['maxIndices']) . "<br>";
echo "Min value: " . $result['min'] . "<br>";
echo "Min indices: " . implode(', ', $result['minIndices']) . "<br>";
