import java.util.ArrayList;
import java.util.List;
import java.util.Scanner;

public class PrimeSum {
    private static List<Integer> primeCache = new ArrayList<>();

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        // Input validation
        int inputNumber;
        while (true) {
            System.out.print("Enter a positive integer greater than 1: ");
            try {
                inputNumber = Integer.parseInt(scanner.nextLine());
                if (inputNumber <= 1) {
                    throw new NumberFormatException();
                }
                break;
            } catch (NumberFormatException e) {
                System.out.println("Invalid input. Please enter a positive integer greater than 1.");
            }
        }

        // Calculate and display the sum of prime numbers
        int sum = 0;
        int largestPrime = 0;
        for (int i = 2; i <= inputNumber; i++) {
            if (isPrime(i)) {
                sum += i;
                largestPrime = i;
            }
        }

        System.out.println("Sum of prime numbers: " + sum);
        System.out.println("Largest prime number: " + largestPrime);
    }

    private static boolean isPrime(int number) {
        if (primeCache.contains(number)) {
            return true;
        }
        for (int i = 2; i <= Math.sqrt(number); i++) {
            if (number % i == 0) {
                return false;
            }
        }
        primeCache.add(number);
        return true;
    }
}
```

