def permute(nums):
    if len(nums) <= 1:
        return [nums]

    permutations = []
    for i in range(len(nums)):
        v = nums[i]
        left = nums[:i] + nums[i+1:]
        subpermute = permute(left)
        for item in subpermute:
            permutations.append([v] + item)
    return permutations

