  let factors = [];
  let count = 0;
  let sumOfSquares = 0;

  for (let i = 2; i <= Math.sqrt(num); i++) {
    if (num % i === 0 && isPrime(i)) {
      factors.push(i);
      count++;
      sumOfSquares += i * i;
    }
  }

  return {
    distinctPrimeFactors: factors,
    countOfDistinctPrimeFactors: count,
    sumOfSquaresOfDistinctPrimeFactors: sumOfSquares
  };
}

