def create_prime_matrix(n):
    if not is_prime(n):
        raise ValueError("N must be a prime number.")

    matrix = [[0 for _ in range(n)] for _ in range(n)]

    for i in range(n):
        matrix[i][i] = 1

    prime = 2
    for i in range(n):
        for j in range(n):
            if matrix[i][j] == 0:
                while not is_prime(prime):
                    prime += 1
                matrix[i][j] = prime
                prime += 1

    return matrix
