import java.util.ArrayList;

public class PrimeSumCalculator {
    public static double calculatePrimeSum(int[] array) {
        ArrayList<Integer> primes = new ArrayList<>();

        for (int num : array) {
            if (isPrime(num)) {
                primes.add(num);
            }
        }

        double sum = 0;
        for (int prime : primes) {
            if (prime % 3 != 0) {
                sum += prime;
            }
        }

        return sum;
    }

    private static boolean isPrime(int num) {
        if (num <= 1) {
            return false;
        }

        if (num == 2 || num == 3) {
            return true;
        }

        if (num % 2 == 0 || num % 3 == 0) {
            return false;
        }

        int sqrt = (int) Math.sqrt(num) + 1;
        for (int i = 6; i <= sqrt; i += 6) {
            if (num % (i - 1) == 0 || num % (i + 1) == 0) {
                return false;
            }
        }

        return true;
    }

    public static void main(String[] args) {
        int[] array = {2, 3, 5, -7, -10, 11, 12, -13, 17};
        double primeSum = calculatePrimeSum(array);
        System.out.println("Prime Sum: " + primeSum);
    }
}
