int main() {
    int n;

    printf("Enter the height of the pyramid: ");
    scanf("%d", &n);

    if (n < 4) {
        printf("The height of the pyramid should be greater than or equal to 4.\n");
        return 0;
    }

    int pyramid[n][n];

    // Initialize the pyramid with 0
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            pyramid[i][j] = 0;
        }
    }

    // Calculate the pyramid values
    for (int i = n - 1; i >= 0; i--) {
        for (int j = 0; j <= i; j++) {
            if (i == n - 1) {
                pyramid[i][j] = j;
            } else {
                pyramid[i][j] = pyramid[i + 1][j] + pyramid[i + 1][j + 1] + pyramid[i + 1][j + 2];
            }
        }
    }

    // Print the pyramid
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n - i - 1; j++) {
            printf("  ");
        }

        for (int j = 0; j <= i; j++) {
            printf("%d ", pyramid[i][j]);
        }

        printf("\n");
    }

    return 0;
}
