```javascript
function binarySearchDescending(arr, target) {
  let left = 0;
  let right = arr.length - 1;

  while (left <= right) {
    const mid = Math.floor((left + right) / 2);

    if (arr[mid] === target) {
      // Check if this is the first occurrence
      let index = mid;
      while (arr[index - 1] === target) {
        index--;
      }
      return index;
    }

    if (arr[mid] < target) {
      right = mid - 1;
    } else {
      left = mid + 1;
    }
  }

  return -1;
}
