function findRemainder(dividend, divisor) {
  // Convert inputs to positive numbers
  dividend = Math.abs(dividend);
  divisor = Math.abs(divisor);

  // Find the whole number quotient
  let quotient = Math.floor(dividend / divisor);

  // Find the remainder by subtracting the product of quotient and divisor from dividend
  let remainder = dividend - (quotient * divisor);

  // Round the remainder to the nearest integer
  remainder = Math.round(remainder);

  // If dividend is negative, make remainder negative as well
  if (dividend < 0) {
    remainder = -remainder;
  }

  return remainder;
}

