        // Loop to print each row of the pyramid
        for (int i = 1; i <= rowCount; i++) {
            // Print spaces before the asterisks
            for (int j = rowCount - i; j > 0; j--) {
                System.out.print(" ");
            }

            // Print the left side of the pyramid (including hollow center)
            for (int j = 1; j <= i; j++) {
