    int weightsLength = weights.length;

    if (numbersLength == 0 || weightsLength == 0) {
        return 0;
    }

    if (numbersLength != weightsLength) {
        throw new IllegalArgumentException("Arrays must have the same length");
    }

    double weightedSum = 0;
