```python
def is_prime(num):
    if num <= 1:
        return False
    for i in range(2, int(num**0.5) + 1):
        if num % i == 0:
            return False
    return True

def generate_fibonacci_numbers(n):
    fib_numbers = [0, 1]
    while len(fib_numbers) < n:
        next_number = fib_numbers[-1] + fib_numbers[-2]
        fib_numbers.append(next_number)
    return fib_numbers

def prime_fibonacci_squares(n):
    prime_fib_squares = []
    fib_numbers = generate_fibonacci_numbers(2 * n)
    for num in fib_numbers:
        if is_prime(num):
            square = num ** 2
            prime_fib_squares.append(square)
            if len(prime_fib_squares) == n:
                break
    product = 1
    for square in prime_fib_squares:
        product *= square
    return prime_fib_squares, product

