int add(int a, int b) {
    // Base case: if one of the numbers is 0, return the other number
    if (b == 0)
        return a;

    // Addition without carry: XOR the numbers
    int sum = a ^ b;

    // Carry: AND the numbers and left shift the result by 1
    int carry = (a & b) << 1;

    // Recursive call with the sum and carry
    return add(sum, carry);
}

bool isInteger(char *str) {
    // Check if the string is empty or only contains whitespace characters
    if (str[0] == '\0' || str[0] == '\n')
        return false;

    // Check if the string starts with a '-' sign
    if (str[0] == '-') {
        if (str[1] == '\0' || str[1] == '\n')
            return false;
        str++; // Skip the '-' sign
    }

    // Check if the string contains digits only
    while (*str != '\0' && *str != '\n') {
        if (*str < '0' || *str > '9')
            return false;
        str++;
    }

    return true;
}
