Here's the JavaScript program that implements this algorithm:

```javascript
function sumOfPrimes(n) {
  // Initialize the sieve array with all values set to true
  const sieve = new Array(n).fill(true);

  // 0 and 1 are not prime numbers
  sieve[0] = false;
  sieve[1] = false;

  let sum = 0;
  let largestPrime = 0;

  for (let i = 2; i < n; i++) {
    if (sieve[i]) {
      // i is a prime number
      sum += i;
      largestPrime = i;

      // Mark all multiples of i as non-prime
      for (let j = i * i; j < n; j += i) {
        sieve[j] = false;
      }
    }
  }

  return { sum, largestPrime };
}

