```php
function radixSort($arr) {
    $positive = [];
    $negative = [];
    $float = [];

    // Separate positive, negative, and floating-point numbers
    foreach ($arr as $num) {
        if ($num >= 0 && is_int($num)) {
            $positive[] = $num;
        } elseif ($num < 0 && is_int($num)) {
            $negative[] = $num;
        } elseif (is_float($num)) {
            $float[] = $num;
        }
    }

    // Sort positive and negative numbers using radix sort
    $positive = radixSortPositive($positive);
    $negative = radixSortNegative($negative);

    // Merge positive and negative numbers
    $result = array_merge($negative, $positive);

    // Sort floating-point numbers using built-in sort
    sort($float);

    // Merge floating-point numbers with the result array
    $result = array_merge($result, $float);

    return $result;
}

function radixSortPositive($arr) {
    // Find the maximum number of digits in the array
    $maxDigits = 0;
    foreach ($arr as $num) {
        $numDigits = strlen((string) $num);
        if ($numDigits > $maxDigits) {
            $maxDigits = $numDigits;
        }
    }

    // Perform counting sort for each digit
    $exp = 1;
    for ($i = 0; $i < $maxDigits; $i++) {
        $buckets = array_fill(0, 10, []);

        foreach ($arr as $num) {
            $digit = ($num / $exp) % 10;
            $buckets[$digit][] = $num;
        }

        $arr = [];
        foreach ($buckets as $bucket) {
            $arr = array_merge($arr, $bucket);
        }

        $exp *= 10;
    }

    return $arr;
}

function radixSortNegative($arr) {
    // Find the maximum number of digits in the array
    $maxDigits = 0;
    foreach ($arr as $num) {
        $numDigits = strlen((string) abs($num));
        if ($numDigits > $maxDigits) {
            $maxDigits = $numDigits;
        }
    }

    // Perform counting sort for each digit
    $exp = 1;
    for ($i = 0; $i < $maxDigits; $i++) {
        $buckets = array_fill(0, 10, []);

        foreach ($arr as $num) {
            $digit = (abs($num) / $exp) % 10;
            $buckets[$digit][] = $num;
        }

        $arr = [];
        foreach ($buckets as $bucket) {
            $arr = array_merge($arr, $bucket);
        }

        $exp *= 10;
    }

    // Reverse the sorted array to get the ascending order
    return array_reverse($arr);
}

