```csharp
using System;

class Program
{
    static void Main(string[] args)
    {
        string str = "aabbA";
        string result = RemoveAdjacentDuplicates(str);
        Console.WriteLine(result);
    }

    static string RemoveAdjacentDuplicates(string str)
    {
        // Convert string to character array
        char[] arr = str.ToCharArray();

        // Initialize variables
        int n = arr.Length;
        int j = 0;

        // Iterate through the character array
        for (int i = 1; i < n; i++)
        {
            // Check if current character is different from previous character
            if (arr[j] != arr[i])
            {
                // Increment j and copy current character to arr[j]
                j++;
                arr[j] = arr[i];
            }
            else
            {
                // Found adjacent duplicates, skip both characters
                j--;
            }
        }

        // Create a new string using the characters in arr up to index j
        return new string(arr, 0, j + 1);
    }
}
