std::string removeVowelsAndDigits(std::string input) {
    std::string vowels = "AEIOUaeiou";
    std::string digits[10] = {"Zero", "One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine"};

    // Remove vowels
    for (char c : vowels) {
        input.erase(std::remove(input.begin(), input.end(), c), input.end());
    }

    // Replace digits with English words
    for (int i = 0; i < 10; i++) {
        char digit = '0' + i;
        std::string digitWord = digits[i];
        size_t pos = input.find(digit);
        while (pos != std::string::npos) {
            input.replace(pos, 1, digitWord);
            pos = input.find(digit, pos + digitWord.length());
        }
    }

    // Reverse words and capitalize first letter
    std::reverse(input.begin(), input.end());
    for (size_t i = 0; i < input.length(); i++) {
        if (isalpha(input[i])) {
            input[i] = toupper(input[i]);
            size_t start = i;
            while (i < input.length() && isalpha(input[i])) {
                i++;
            }
            std::reverse(input.begin() + start, input.begin() + i);
        }
    }

    // Remove consecutive duplicate letters
    for (size_t i = 1; i < input.length(); i++) {
        if (input[i] == input[i - 1]) {
            input.erase(i, 1);
            i--;
        }
    }

    return input;
}

