import java.util.HashMap;

public class ReverseHashMap {
    public static void main(String[] args) {
        // Create a HashMap
        HashMap<String, String> hashMap = new HashMap<>();

        // Add key-value pairs to the HashMap
        hashMap.put("key1", "value1");
        hashMap.put("key2", "value2");
        hashMap.put("key3", "value3");
        hashMap.put("key4", "value4");
        hashMap.put("key1", "value5"); // Duplicate key

        // Get the keys in reverse order
        String[] keys = new String[hashMap.size()];
        int index = 0;
        for (String key : hashMap.keySet()) {
            keys[hashMap.size() - index - 1] = key;
            index++;
        }

        // Iterate through the keys and print the keys and values in reverse order
        for (String key : keys) {
            String value = hashMap.get(key);
            System.out.println("Key: " + key + ", Value: " + value);
        }
    }
}
