```javascript
function setMarginToZero(element, className) {
  var startTime = Date.now();

  // Check if the element has the specified class name
  if (element.classList.contains(className)) {
    element.style.margin = '0';
  } else {
    // Check if the element has any child elements with the same class name
    var childElements = element.getElementsByClassName(className);
    if (childElements.length > 0) {
      for (var i = 0; i < childElements.length; i++) {
        childElements[i].style.margin = '0';
      }
    } else {
      // Traverse up the DOM tree to find the closest parent element with the specified class name
      var parentElement = element.parentElement;
      while (parentElement !== null && !parentElement.classList.contains(className)) {
        parentElement = parentElement.parentElement;
      }
      if (parentElement !== null) {
        parentElement.style.margin = '0';
      } else {
        console.error('Class name not found in any parent elements');
        return;
      }
    }
  }

  var endTime = Date.now();
  var executionTime = endTime - startTime;

  // Check if the execution time exceeds the time constraint
  if (executionTime > 100) {
    console.error('Execution time exceeded the limit');
  }
}
```

This implementation uses various DOM methods like `classList.contains()`, `getElementsByClassName()`, and `parentElement` to check for the presence of the specified class name in the element and its parent elements. It also uses the `style.margin` property to set the margin to 0.

