Here's one way to implement the separateNumbers function in JavaScript:

```javascript
function separateNumbers(numbers) {
  var primeNumbers = [];
  var compositeNumbers = [];
  var perfectNumbers = [];

  for (var i = 0; i < numbers.length; i++) {
    var number = numbers[i];

    if (isPrime(number)) {
      primeNumbers.push(number);
    } else if (isComposite(number)) {
      compositeNumbers.push(number);
    } else if (isPerfect(number)) {
      perfectNumbers.push(number);
    }
  }

  primeNumbers.sort((a, b) => a - b);
  compositeNumbers.sort((a, b) => a - b);
  perfectNumbers.sort((a, b) => a - b);

  return {
    primeNumbers: primeNumbers,
    compositeNumbers: compositeNumbers,
    perfectNumbers: perfectNumbers
  };
}

function isPrime(number) {
  if (number < 2) {
    return false;
  }

  for (var i = 2; i <= Math.sqrt(number); i++) {
    if (number % i === 0) {
      return false;
    }
  }

  return true;
}

function isComposite(number) {
  if (number < 4) {
    return false;
  }

  for (var i = 2; i <= Math.sqrt(number); i++) {
    if (number % i === 0) {
      return true;
    }
  }

  return false;
}

function isPerfect(number) {
  if (number < 6) {
    return false;
  }

  var sum = 1;

  for (var i = 2; i <= Math.sqrt(number); i++) {
    if (number % i === 0) {
      sum += i;

      if (i !== number / i) {
        sum += number / i;
      }
    }
  }

  return sum === number;
}

