function findThirdLargestNumber(arr) {
  if (arr.length < 3) {
    return "Array length should be at least 3.";
  }

  let largest = Number.MIN_SAFE_INTEGER;
  let secondLargest = Number.MIN_SAFE_INTEGER;
  let thirdLargest = Number.MIN_SAFE_INTEGER;

  for (let i = 0; i < arr.length; i++) {
    if (arr[i] > largest) {
      thirdLargest = secondLargest;
      secondLargest = largest;
      largest = arr[i];
    } else if (arr[i] > secondLargest && arr[i] < largest) {
      thirdLargest = secondLargest;
      secondLargest = arr[i];
    } else if (arr[i] > thirdLargest && arr[i] < secondLargest) {
      thirdLargest = arr[i];
    }
  }

  if (thirdLargest === Number.MIN_SAFE_INTEGER) {
    return "There is no third largest number.";
  }

  return thirdLargest;
}
```

Here's how the function works:

1. We start by initializing three variables `largest`, `secondLargest`, and `thirdLargest` to `Number.MIN_SAFE_INTEGER` which is the smallest possible integer value.
2. We iterate over the input array using a for loop.
3. Inside the loop, we compare each element of the array with the current values of `largest`, `secondLargest`, and `thirdLargest`.
4. If the current element is greater than `largest`, we update all three variables accordingly: `thirdLargest` becomes `secondLargest`, `secondLargest` becomes `largest`, and `largest` becomes the current element.
5. If the current element is greater than `secondLargest` but less than `largest`, we update `thirdLargest` and `secondLargest` accordingly.
6. If the current element is greater than `thirdLargest` but less than `secondLargest`, we update `thirdLargest`.
7. After iterating over all the elements of the array, if `thirdLargest` is still equal to `Number.MIN_SAFE_INTEGER`, it means there is no third largest number in the array, so we return a message indicating that.
8. Otherwise, we return the value of `thirdLargest`.

