public class MultiplyWithoutOperator {
    public static int multiply(int a, int b) {
        // Initialize the result variable
        int result = 0;

        // Iterate through each bit of the second number
        while (b != 0) {
            // If the current bit is set (1), add the first number to the result
            if ((b & 1) != 0) {
                result = add(result, a);
            }

            // Shift the first number to the left by 1 bit
            a <<= 1;

            // Shift the second number to the right by 1 bit
            b >>= 1;
        }

        return result;
    }

    // Helper function to add two numbers using bitwise operations
    private static int add(int a, int b) {
        while (b != 0) {
            // Carry contains common set bits of a and b
            int carry = a & b;

            // Sum of bits of a and b where at least one of the bits is not set
            a = a ^ b;

            // Carry is shifted by one so that adding it to a gives the required sum
            b = carry << 1;
        }

        return a;
    }

    public static void main(String[] args) {
        int a = 5;
        int b = 8;
        int result = multiply(a, b);
        System.out.println("Product: " + result);
    }
}
