class HashMap:

    def __init__(self, size): 
        self.size = size 
        self.map = [None] * size

    def _get_hash(self, key):
        hashCode = 0
        for char in key:
            hashCode += ord(char)
        return hashCode % self.size

    def add(self, key, value):
        keyHash = self._get_hash(key)

        keyValue = [key, value]
        if self.map[keyHash] is None:
            self.map[keyHash] = list([keyValue])
            return True
        else:
            for pair in self.map[keyHash]:
                if pair[0] == key:
                    pair[1] = value
                    return True
            self.map[keyHash].append(keyValue)
            return True

    def get(self, key):
        keyHash = self._get_hash(key)
        if self.map[keyHash] is None:
            return None
        else:
            for pair in self.map[keyHash]:
                if pair[0] == key:
                    return pair[1]
        return None

