```java
public class SpiralOrder {
    public static void main(String[] args) {
        int[][] array = {
                { 1, 2, 3 },
                { 8, 9, 4 },
                { 7, 6, 5 }
        };

        printSpiralOrder(array);
    }

    public static void printSpiralOrder(int[][] array) {
        int n = array.length;
        int totalSum = n * (n * n + 1) / 2; // Sum of numbers from 1 to n^2

        // Validate the array
        if (!validateArray(array, totalSum)) {
            System.out.println("Invalid input array.");
            return;
        }

        int top = 0, bottom = n - 1, left = 0, right = n - 1;
        int direction = 0; // 0 - right, 1 - down, 2 - left, 3 - up

        while (top <= bottom && left <= right) {
            if (direction == 0) {
                // Print top row
                for (int i = left; i <= right; i++) {
                    System.out.print(array[top][i] + " ");
                }
                top++;
            } else if (direction == 1) {
                // Print right column
                for (int i = top; i <= bottom; i++) {
                    System.out.print(array[i][right] + " ");
                }
                right--;
            } else if (direction == 2) {
                // Print bottom row
                for (int i = right; i >= left; i--) {
                    System.out.print(array[bottom][i] + " ");
                }
                bottom--;
            } else if (direction == 3) {
                // Print left column
                for (int i = bottom; i >= top; i--) {
                    System.out.print(array[i][left] + " ");
                }
                left++;
            }

            direction = (direction + 1) % 4;
        }
    }

    public static boolean validateArray(int[][] array, int totalSum) {
        int n = array.length;
        int sumTop = 0, sumRight = 0, sumBottom = 0, sumLeft = 0;

        // Calculate sums of each side of the spiral
        for (int i = 0; i < n; i++) {
            sumTop += array[0][i];
            sumRight += array[i][n - 1];
            sumBottom += array[n - 1][i];
            sumLeft += array[i][0];
        }

        // Check if sums are equal to totalSum
        return sumTop == totalSum && sumRight == totalSum && sumBottom == totalSum && sumLeft == totalSum;
    }
}
```

