  // Create an array of unique numbers
  const uniqueNumbers = Object.keys(frequencyMap);

  // Sort the unique numbers array in descending order using a comparison function
  uniqueNumbers.sort((a, b) => b - a);

  // Create the sorted array by repeating each number according to its frequency
  const sortedArray = [];
  for (let i = 0; i < uniqueNumbers.length; i++) {
    const num = uniqueNumbers[i];
    const frequency = frequencyMap[num];
    sortedArray.push(...Array(frequency).fill(parseInt(num)));
  }

  // Return the sorted array and the count of unique elements
  return {
    sortedArray,
    uniqueCount: uniqueNumbers.length,
  };
}

let numbers = [2, 10, 5, 4, 3, 10, 4, 5, 2, 3];
const result = sortAndRemoveDuplicates(numbers);
console.log("Sorted Array:", result.sortedArray);
console.log("Unique Count:", result.uniqueCount);
