console.log(calculateMedian([5])); // 5
console.log(calculateMedian([1, 1, 1, 1])); // 1
console.log(calculateMedian([2, 3, NaN, 1, undefined])); // 2
console.log(calculateMedian([Infinity, -Infinity, 2, 3])); // 2.5
```

