using System;

public class InvalidTriangleException : Exception
{
    public InvalidTriangleException(string message) : base(message)
    {
    }
}

public class Triangle
{
    public static string FindTriangleType(double side1, double side2, double side3)
    {
        if (side1 <= 0 || side2 <= 0 || side3 <= 0)
        {
            throw new InvalidTriangleException("Side lengths cannot be negative or zero.");
        }

        if (side1 + side2 <= side3 || side1 + side3 <= side2 || side2 + side3 <= side1)
        {
            throw new InvalidTriangleException("The given side lengths do not form a valid triangle.");
        }

        if (side1 == side2 && side2 == side3)
        {
            return "Equilateral triangle";
        }
        else if (side1 == side2 || side1 == side3 || side2 == side3)
        {
            return "Isosceles triangle";
        }
        else
        {
            return "Scalene triangle";
        }
    }

    public static double FindTriangleArea(double side1, double side2, double side3)
    {
        if (side1 <= 0 || side2 <= 0 || side3 <= 0)
        {
            throw new InvalidTriangleException("Side lengths cannot be negative or zero.");
        }

        if (side1 + side2 <= side3 || side1 + side3 <= side2 || side2 + side3 <= side1)
        {
            throw new InvalidTriangleException("The given side lengths do not form a valid triangle.");
        }

        double s = (side1 + side2 + side3) / 2;
        double area = Math.Sqrt(s * (s - side1) * (s - side2) * (s - side3));
        return area;
    }
}

public class Program
{
    public static void Main()
    {
        try
        {
            double side1 = 3;
            double side2 = 4;
            double side3 = 5;

