        int largestPrime = -1;

        // Check if each number is prime and find the largest one
        if (isPrime(num1) && num1 > largestPrime) {
            largestPrime = num1;
        }
        if (isPrime(num2) && num2 > largestPrime) {
            largestPrime = num2;
        }
        if (isPrime(num3) && num3 > largestPrime) {
            largestPrime = num3;
        }

        return largestPrime;
    }

    public static boolean isPrime(int number) {
        if (number <= 1) {
            return false;
        }

        // Check if the number is divisible by any number from 2 to its square root
        for (int i = 2; i <= Math.sqrt(number); i++) {
            if (number % i == 0) {
                return false;
            }
        }

        return true;
    }
}
