int romanToDecimal(const std::string& roman) {
    int result = 0;
    int prevValue = 0;
    for (int i = roman.size() - 1; i >= 0; i--) {
        int currentValue = romanNumerals[roman[i]];
        if (currentValue < prevValue) {
            result -= currentValue;
        }
        else {
            result += currentValue;
            prevValue = currentValue;
        }
    }
    return result;
}

