public class Addition {

    private static final long MAX_VALUE = Long.MAX_VALUE;

    public static double addWithOverflowCheck(int num1, int num2) {
        long sum = addUsingBitwise(num1, num2);

        if (sum > MAX_VALUE) {
            throw new ArithmeticException("Overflow occurred");
        }

        return (double) sum;
    }

    private static long addUsingBitwise(int num1, int num2) {
        long result = 0;
        int carry = 0;

        for (int i = 0; i < 32; i++) {
            int bit1 = (num1 >> i) & 1;
            int bit2 = (num2 >> i) & 1;

            // Calculate the sum and carry using bitwise operations
            int sum = (bit1 ^ bit2) ^ carry;
            carry = (bit1 & bit2) | (carry & (bit1 ^ bit2));

            // Update the result using bitwise operations
            result |= (sum << i);
        }

        return result;
    }

    public static void main(String[] args) {
        int num1 = 123456789;
        int num2 = 987654321;

        try {
            double sum = addWithOverflowCheck(num1, num2);
            System.out.println("Sum: " + sum);
        } catch (ArithmeticException e) {
            System.out.println(e.getMessage());
        }
    }
}
