import java.util.regex.*;

public class ReplaceNonAlphanumeric {
    public static void main(String[] args) {
        String input = "\"Hello, [Wor!ld!]\" \"This is a [Te!st!]\"";
        String output = replaceNonAlphanumeric(input);
        System.out.println(output);
    }

    public static String replaceNonAlphanumeric(String input) {
        Pattern pattern = Pattern.compile("\"(.*?)\"|\\[(.*?)\\]|[^a-zA-Z0-9\\[\\]\" ]");
        Matcher matcher = pattern.matcher(input);
        StringBuffer result = new StringBuffer();

        while (matcher.find()) {
            String match = matcher.group();
            if (match.startsWith("\"") && match.endsWith("\"")) {
                matcher.appendReplacement(result, match);
            } else if (match.startsWith("[") && match.endsWith("]")) {
                matcher.appendReplacement(result, match);
            } else {
                String replacement = match.replaceAll("[^a-zA-Z0-9]", "_").toLowerCase();
                matcher.appendReplacement(result, replacement);
            }
        }

        matcher.appendTail(result);
        return result.toString();
    }
}
