    def __init__(self, val):
        self.val = val
        self.left = None
        self.right = None
        self.height = 1


def construct_AVL_tree(arr):
    if not arr:
        return None

    mid = len(arr) // 2
    root = Node(arr[mid])

    root.left = construct_AVL_tree(arr[:mid])
    root.right = construct_AVL_tree(arr[mid + 1:])

    root.height = 1 + max(get_height(root.left), get_height(root.right))

    balance_factor = get_balance_factor(root)

    # Perform necessary rotations to maintain balance
    if balance_factor > 1 and arr[mid] < root.left.val:
        return rotate_right(root)

    if balance_factor < -1 and arr[mid] > root.right.val:
        return rotate_left(root)

    if balance_factor > 1 and arr[mid] > root.left.val:
        root.left = rotate_left(root.left)
        return rotate_right(root)

    if balance_factor < -1 and arr[mid] < root.right.val:
        root.right = rotate_right(root.right)
        return rotate_left(root)

    return root


