      capitalLetterCount++;
      if (capitalLetterCount >= 3) {
        break;
      }
    }
  }

  // Check if the string contains consecutive repeating characters
  for (let i = 1; i < str.length; i++) {
    if (str[i] === str[i - 1]) {
      return false;
    }
  }

  // Check if the string contains any whitespace characters
