Here is an implementation of the Merge Sort algorithm in C# that sorts an array of integers in descending order using a recursive approach:

```csharp
public class MergeSortDescending
{
    public static void Sort(int[] array)
    {
        if (array == null || array.Length <= 1)
            return;

        int[] sortedArray = MergeSort(array);
        Array.Copy(sortedArray, array, array.Length);
    }

    private static int[] MergeSort(int[] array)
    {
        if (array.Length <= 1)
            return array;

        int mid = array.Length / 2;
        int[] left = new int[mid];
        int[] right = new int[array.Length - mid];

        Array.Copy(array, 0, left, 0, left.Length);
        Array.Copy(array, mid, right, 0, right.Length);

        left = MergeSort(left);
        right = MergeSort(right);

        return Merge(left, right);
    }

    private static int[] Merge(int[] left, int[] right)
    {
        int leftLength = left.Length;
        int rightLength = right.Length;
        int[] mergedArray = new int[leftLength + rightLength];

        int i = 0, j = 0, k = 0;

        while (i < leftLength && j < rightLength)
        {
            if (left[i] >= right[j])
                mergedArray[k++] = left[i++];
            else
                mergedArray[k++] = right[j++];
        }

        while (i < leftLength)
            mergedArray[k++] = left[i++];

        while (j < rightLength)
            mergedArray[k++] = right[j++];

        return mergedArray;
    }
}
```

