function swapAndReverse(array) {
  // Swap first and last elements
  let temp = array[0];
  array[0] = array[array.length - 1];
  array[array.length - 1] = temp;

  // Reverse the order of elements in between the first and last elements
  let start = 1;
  let end = array.length - 2;
  while (start < end) {
    temp = array[start];
    array[start] = array[end];
    array[end] = temp;
    start++;
    end--;
  }

  return array;
}

