    public static int calculateEvenFibonacciSum(int N) {
        int sum = 0;
        int a = 2; // First even Fibonacci number
        int b = 8; // Second even Fibonacci number

        if (N == 1) {
            return a;
        } else if (N == 2) {
            return a + b;
        }

        sum = a + b;

        for (int i = 3; i <= N; i++) {
            int c = 4 * b + a; // Calculate the next even Fibonacci number

            sum += c;

            a = b;
            b = c;
        }

        return sum;
    }
}

