public class AnagramChecker {
    public static boolean areAnagrams(String str1, String str2) {
        // Remove punctuation marks and special characters
        str1 = removeSpecialCharacters(str1);
        str2 = removeSpecialCharacters(str2);

        // Ignore case
        str1 = str1.toLowerCase();
        str2 = str2.toLowerCase();

        // Remove whitespace characters
        str1 = removeWhitespaces(str1);
        str2 = removeWhitespaces(str2);

        // Check if the strings have the same length
        if (str1.length() != str2.length()) {
            return false;
        }

        // Count the occurrence of each character in str1
        int[] charCount = new int[26];
        for (int i = 0; i < str1.length(); i++) {
            char c = str1.charAt(i);
            charCount[c - 'a']++;
        }

        // Compare the occurrence of each character in str2
        for (int i = 0; i < str2.length(); i++) {
            char c = str2.charAt(i);
            charCount[c - 'a']--;
            if (charCount[c - 'a'] < 0) {
                return false;
            }
        }

        return true;
    }

    private static String removeSpecialCharacters(String str) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < str.length(); i++) {
            char c = str.charAt(i);
            if (Character.isLetterOrDigit(c)) {
                sb.append(c);
            }
        }
        return sb.toString();
    }

    private static String removeWhitespaces(String str) {
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < str.length(); i++) {
            char c = str.charAt(i);
            if (!Character.isWhitespace(c)) {
                sb.append(c);
            }
        }
        return sb.toString();
    }

