function reorderArray(arr) {
  // Helper function to determine length
  const getLength = (str) => str.length;

  // Calculate frequency count
  const count = {};
  arr.forEach((item) => {
    count[item] = count[item] ? count[item] + 1 : 1;
  });

  // Custom comparator function
  const compare = (a, b) => {
    const lengthDiff = getLength(a) - getLength(b);
    if (lengthDiff !== 0) {
      return lengthDiff;
    }

    const alphabeticalDiff = a.localeCompare(b);
    if (alphabeticalDiff !== 0) {
