            return False
        i += 6
    return True

def find_largest_prime(arr):
    left = 0
    right = len(arr) - 1

    while left <= right:
        mid = (left + right) >> 1
        if is_prime(arr[mid]):
            return arr[mid]
        elif arr[mid] > 2:
            right = mid - 1
        else:
            left = mid + 1

    return None
```

