Here's the C# program to calculate the sum of the first n Fibonacci numbers, with input validation and efficient handling of large numbers:

```csharp
using System;
using System.Numerics;

class FibonacciSum
{
    static void Main()
    {
        Console.Write("Enter the value of n (greater than or equal to 3): ");
        if (int.TryParse(Console.ReadLine(), out int n) && n >= 3)
        {
            BigInteger sum = CalculateFibonacciSum(n);
            Console.WriteLine("Sum of the first {0} Fibonacci numbers: {1}", n, sum);
        }
        else
        {
            Console.WriteLine("Invalid input. Please enter a positive integer greater than or equal to 3.");
        }
    }

    static BigInteger CalculateFibonacciSum(int n)
    {
        BigInteger a = 1;
        BigInteger b = 1;
        BigInteger sum = 2;

        for (int i = 3; i <= n; i++)
        {
            BigInteger temp = a + b;
            sum += temp;
            a = b;
            b = temp;
        }

        return sum;
    }
}
