function convertObjectToList(obj) {
  const result = [];

  function traverse(obj, depth) {
    if (depth > 3) {
      return;
    }

    for (const key in obj) {
      if (typeof obj[key] === "object" && obj[key] !== null) {
        if (Array.isArray(obj[key])) {
          result.push(`${key}:array:[${obj[key]}]`);
        } else {
          result.push(`${key}:object:{${traverse(obj[key], depth + 1)}}`);
        }
      } else {
        result.push(`${key}:${typeof obj[key]}:${obj[key]}`);
      }
    }
  }

  traverse(obj, 0);
  return result;
}
