def is_prime(n):
    if n <= 1:
        return False
    if n == 2:
        return True
    if n % 2 == 0:
        return False
    for i in range(3, int(n**0.5) + 1, 2):
        if n % i == 0:
            return False
    return True

def is_palindrome(n):
    return str(n) == str(n)[::-1]

def contains_even_digit(n):
    digits = str(n)
    for digit in digits:
        if int(digit) % 2 == 0:
            return True
    return False

