    for num in range(1, 1000):
        if is_prime(num) and is_palindrome(num) and contains_even_digit(num):
            # Check if the number is the sum of two prime numbers
            for i in range(2, num//2 + 1):
                if is_prime(i) and is_prime(num - i):
