```javascript
function reverseStringWithTimestamp(string, secretKey) {
  const debugMode = secretKey === 'your-secret-key'; // Change 'your-secret-key' with your desired secret key

  if (debugMode) {
    const reversedWords = string.split(' ').map(word => {
      const reversedWord = word.split('').reverse().join('');
      const firstChar = word.charAt(0);
      const lastChar = word.charAt(word.length - 1);

      // Preserve punctuation and capitalization
      if (word.length > 1 && isPunctuation(lastChar)) {
        return lastChar + reversedWord.slice(1, -1) + firstChar;
      } else if (isPunctuation(firstChar)) {
        return reversedWord.slice(0, -1) + firstChar + lastChar;
      } else {
        return reversedWord;
      }
    });

    const reversedString = reversedWords.join(' ');

    const timestamp = new Date().toISOString().slice(0, 19).replace('T', ' ');

    return `${reversedString} (${timestamp})`;
  }

  return string;
}

function isPunctuation(char) {
  const punctuation = '.,;:!?';
  return punctuation.includes(char);
}
