function create2DArray(m, n) {
  // Helper function to check if a number is prime
  function isPrime(num) {
    for (let i = 2, sqrt = Math.sqrt(num); i <= sqrt; i++) {
      if (num % i === 0) {
        return false;
      }
    }
    return num > 1;
  }

  // Helper function to get the sum of prime factors of a number
  function getPrimeFactorsSum(num) {
    let sum = 0;
    for (let i = 2; i <= num; i++) {
      if (isPrime(i) && num % i === 0) {
        sum += i;
      }
    }
    return sum;
  }

  // Create the 2D array
  const arr = [];
  const set = new Set();
  while (arr.length < m) {
    const row = [];
    while (row.length < n) {
      const num = Math.floor(Math.random() * 10001);
      if (!set.has(num)) {
        row.push(num);
        set.add(num);
      }
    }
    arr.push(row);
  }

  // Sort the array based on the sum of prime factors
  arr.sort((a, b) => {
    const sumA = a.reduce((acc, curr) => acc + getPrimeFactorsSum(curr), 0);
    const sumB = b.reduce((acc, curr) => acc + getPrimeFactorsSum(curr), 0);
    return sumA - sumB;
  });

  return arr;
}
```

