from bs4 import BeautifulSoup, Tag

def parse_html(html_code, indent=0):
    soup = BeautifulSoup(html_code, 'html.parser')
    result = ""

    for tag in soup.children:
        if isinstance(tag, Tag):
            result += indent * "  " + "<" + tag.name

            if tag.attrs:
                for attr, value in tag.attrs.items():
                    result += f' {attr}="{value}"'

            result += ">"

            if tag.name != "style":
                result += "\n"

            if tag.name == "style":
                result += "\n" + tag.text.strip() + "\n"
            elif tag.contents:
                if len(tag.contents) > 1:
                    result += parse_html(tag.prettify(), indent + 1)
                else:
                    result += parse_html(str(tag.contents[0]), indent + 1)

            result += indent * "  " + "</" + tag.name + ">\n"

    return result

def decompile_html(html_code):
    try:
        parsed_html = parse_html(html_code)
        return parsed_html
    except Exception as e:
        return f"Error: {str(e)}"

