```cpp
#include <iostream>
#include <vector>

std::vector<int> maxSubarraySum(const std::vector<int>& arr) {
    int n = arr.size();
    int maxSum = INT_MIN, currSum = 0;
    int start = 0, end = -1;

    for (int i = 0, j = 0; j < n; j++) {
        currSum += arr[j];

        if (currSum > maxSum) {
            maxSum = currSum;
            start = i;
            end = j;
        }

        if (currSum < 0) {
            currSum = 0;
            i = j + 1;
        }
    }

    return {start, end, maxSum};
}

int main() {
    std::vector<int> arr = {-2, -3, 4, -1, -2, 1, 5, -3};
    std::vector<int> result = maxSubarraySum(arr);

    std::cout << "Subarray with maximum sum: ";
    for (int i = result[0]; i <= result[1]; i++) {
        std::cout << arr[i] << " ";
    }
    std::cout << "\nMaximum sum: " << result[2] << std::endl;

    return 0;
}
```

This code uses the Kadane's algorithm to find the maximum subarray sum in linear time complexity (O(n)). It keeps track of the current sum and updates it if it becomes negative. Whenever the current sum becomes greater than the maximum sum, it updates the maximum sum and the corresponding start and end indices.

