class HashTable:
    def __init__(self):
        self.size = 10
        self.table = [[] for _ in range(self.size)]

    def _hash(self, key):
        hash_value = 0
        if isinstance(key, str):
            for char in key:
                hash_value += ord(char)
        else:
            hash_value = key
        return hash_value % self.size

    def add(self, key, value):
        hash_key = self._hash(key)
        for item in self.table[hash_key]:
            if item[0] == key:
                item[1] = value
                return
        self.table[hash_key].append([key, value])

    def remove(self, key):
        hash_key = self._hash(key)
        for index, item in enumerate(self.table[hash_key]):
            if item[0] == key:
                del self.table[hash_key][index]
                return

    def update(self, key, value):
        hash_key = self._hash(key)
        for item in self.table[hash_key]:
            if item[0] == key:
                item[1] = value
                return

    def retrieve(self, key):
        hash_key = self._hash(key)
        for item in self.table[hash_key]:
            if item[0] == key:
                return item[1]
        return None

    def exists(self, key):
        hash_key = self._hash(key)
        for item in self.table[hash_key]:
            if item[0] == key:
                return True
        return False


