switch result1 {
case .success(let splitStrings):
    print(splitStrings) // Output: ["def", "ghi"]
case .failure(let errorMessage):
    print(errorMessage)
}

let result2 = splitString("abcdefghi", by: "xyz")
switch result2 {
case .success(let splitStrings):
    print(splitStrings)
case .failure(let errorMessage):
    print(errorMessage) // Output: Delimiter not found
}

let result3 = splitString("", by: "abc")
switch result3 {
case .success(let splitStrings):
    print(splitStrings)
case .failure(let errorMessage):
    print(errorMessage) // Output: String is empty
}
```

In the first example, the delimiter "abc" is found multiple times consecutively in the input string, and the resulting split strings are printed.

In the second example, the delimiter "xyz" is not found in the input string, and the failure case with the appropriate error message is printed.

