```cpp
#include <iostream>
#include <vector>

std::vector<int> bubbleSort(std::vector<int> nums) {
    int n = nums.size();
    bool swapped;
    for (int i = 0; i < n-1; i++) {
        swapped = false;
        for (int j = 0; j < n-i-1; j++) {
            if (nums[j] > nums[j+1]) {
                std::swap(nums[j], nums[j+1]);
                swapped = true;
            }
        }
        if (!swapped) {
            break;  // If no swaps were made in this iteration, the array is already sorted
        }
    }
    return nums;
}

int main() {
    std::vector<int> nums = {4, 2, 5, 1, 3};
    std::vector<int> sortedNums = bubbleSort(nums);
    for (int num : sortedNums) {
        std::cout << num << " ";
    }
    std::cout << std::endl;
    return 0;
}
```

Output:
```
1 2 3 4 5
```

This implementation uses a flag called `swapped` to check if any swaps were made during each iteration. If no swaps were made, it means the array is already sorted and the sorting process can be terminated early. This optimization reduces unnecessary iterations and improves performance for arrays that are already sorted or partially sorted.

