import math

class TriangularPrism:
    def __init__(self, length, width, height):
        self.length = length
        self.width = width
        self.height = height

    def calculate_surface_area(self):
        try:
            return 2 * self.length * self.width + 2 * self.width * self.height + 2 * self.length * self.height
        except Exception as e:
            raise Exception("Error calculating surface area: " + str(e))

    def calculate_volume(self):
        try:
            return 0.5 * self.length * self.width * self.height
        except Exception as e:
            raise Exception("Error calculating volume: " + str(e))

def validate_input(prompt):
    while True:
        try:
            value = float(input(prompt))
            if value <= 0:
                print("Invalid input. Please enter a positive number.")
            else:
                return value
        except ValueError:
            print("Invalid input. Please enter a number.")

def main():
    try:
        length = validate_input("Enter the length of the triangular prism: ")
        width = validate_input("Enter the width of the triangular prism: ")
        height = validate_input("Enter the height of the triangular prism: ")

        if length <= height or width <= height:
            raise Exception("Invalid dimensions. The length and width must be greater than the height.")

        prism = TriangularPrism(length, width, height)

        surface_area = prism.calculate_surface_area()
        volume = prism.calculate_volume()

        print("Surface area: ", surface_area)
        print("Volume: ", volume)

    except Exception as e:
        print("An error occurred:", str(e))

if __name__ == "__main__":
    main()
```

